# saml2sp/views.py

from django.shortcuts import redirect
from django.contrib.auth import login, authenticate
from django.http import HttpResponse
from saml2.response import AuthnResponse
from saml2.client import Saml2Client
from .config import SAML_CONFIG

def acs(request):
    client = Saml2Client(config=SAML_CONFIG)
    response = AuthnResponse(client=client, info=request.POST)
    if not response:
        return HttpResponse("Authentication failed", status=401)

    user_info = response.get_identity()
    username = user_info['http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress'][0]
    try:
        user = authenticate(request, username=username)
    except Exception as e:
        return HttpResponse("User authentication failed: {}".format(e), status=401)

    login(request, user)
    return redirect('/')

